import { readdirSync, readFileSync, writeFileSync } from "node:fs";
import { join, relative } from "node:path";

const repoRoot = process.cwd();
const ignoredDirectories = new Set([
  ".git",
  ".forge",
  "coverage",
  "dist",
  "node_modules",
  "worktrees"
]);
const generatedHeader = [
  "<!--",
  "Generated from CLAUDE.md by `node scripts/sync-agents-from-claude.mjs`.",
  "Do not edit this file directly; edit the sibling CLAUDE.md instead.",
  "-->",
  ""
].join("\n");

const claudeFiles = findClaudeFiles(repoRoot);
let updatedCount = 0;

for (const claudeFile of claudeFiles) {
  const agentsFile = claudeFile.replace(/CLAUDE\.md$/u, "AGENTS.md");
  const claudeContents = readFileSync(claudeFile, "utf8");
  const generatedContents = `${generatedHeader}${claudeContents}`;
  const existingContents = readOptionalFile(agentsFile);

  if (existingContents === generatedContents) {
    continue;
  }

  writeFileSync(agentsFile, generatedContents);
  updatedCount += 1;
  console.log(`updated ${relative(repoRoot, agentsFile)}`);
}

if (updatedCount === 0) {
  console.log("AGENTS.md files are up to date");
}

function findClaudeFiles(directory) {
  const files = [];

  for (const entry of readdirSync(directory, { withFileTypes: true })) {
    const path = join(directory, entry.name);

    if (entry.isDirectory()) {
      if (!ignoredDirectories.has(entry.name)) {
        files.push(...findClaudeFiles(path));
      }
      continue;
    }

    if (entry.isFile() && entry.name === "CLAUDE.md") {
      files.push(path);
    }
  }

  return files.sort();
}

function readOptionalFile(file) {
  try {
    return readFileSync(file, "utf8");
  } catch (error) {
    if (error instanceof Error && "code" in error && error.code === "ENOENT") {
      return null;
    }

    throw error;
  }
}
